cd /home/user/project && find . -not -path '.' -not -name 'MANIFEST.md' | sort | sed 's|^./||' | awk '{
  depth = gsub(/\//, "/");
  split($0, parts, "/");
  name = parts[depth+1];
  indent = "";
  for (i = 0; i < depth; i++) indent = indent "  ";
  if (system("test -d \"./" $0 "\"") == 0)
    printf "%s📁 %s/\n", indent, name;
  else
    printf "%s📄 %s\n", indent, name;
}'

